{
  "family": "Ritter Reaction",
  "candidate": {
    "substrate_smiles": [
      "CC(C)(C)O",
      "CC#N"
    ],
    "product_smiles": [
      "CC(=O)NC(C)(C)C"
    ],
    "optional_reagent_smiles": [
      "O=S(=O)(O)O"
    ],
    "rationale": "This is the classical textbook example of the Ritter reaction, featuring the reaction of tert-butanol with acetonitrile in the presence of a strong acid (sulfuric acid). The tert-butanol serves as a stable precursor to the tert-butyl carbocation, which is then trapped by the nitrile. Subsequent hydrolysis of the resulting nitrilium ion intermediate yields the N-tert-butylacetamide product. All reactants and products are simple, acyclic, and RDKit-parseable, clearly illustrating the core transformation of the Ritter reaction.",
    "collision_avoidance_note": "This example uses simple, acyclic aliphatic substrates (tert-butanol and acetonitrile) to avoid overlap with reactions involving aromatic rings, complex ring systems, or other functional groups. The core transformation is the formation of a C-N bond and subsequent conversion of a nitrile to an amide, which is highly characteristic of the Ritter reaction and distinct from other named reactions."
  }
}
